static Instruction *foldAddToAshr(BinaryOperator &Add) {
  // Division must be by power-of-2, but not the minimum signed value.
  Value *X;
  const APInt *DivC;
  if (!match(Add.getOperand(0), m_SDiv(m_Value(X), m_Power2(DivC))) ||
      DivC->isNegative())
    return nullptr;

  // Rounding is done by adding -1 if the dividend (X) is negative and has any
  // low bits set. The canonical pattern for that is an "ugt" compare with SMIN:
  // sext (icmp ugt (X & (SMin | (DivC - 1))), SMin)
  // Or an "eq" compare with the mask:
  // sext (icmp eq (X & (SMin | (DivC - 1))), (SMin | (DivC - 1)))
  const APInt *MaskC;
  ICmpInst::Predicate Pred;
  if (!match(Add.getOperand(1),
             m_SExt(m_ICmp(Pred, m_And(m_Specific(X), m_APInt(MaskC)),
                           m_Value()))) ||
      (Pred != ICmpInst::ICMP_UGT && Pred != ICmpInst::ICMP_EQ))
    return nullptr;

  APInt SMin = APInt::getSignedMinValue(Add.getType()->getScalarSizeInBits());
  APInt ExpectedMask = SMin | (*DivC - 1);
  if (*MaskC != ExpectedMask)
    return nullptr;

  // Verify the comparison operand matches the expected pattern.
  Value *CmpOp1 = cast<ICmpInst>(
      cast<SExtInst>(Add.getOperand(1))->getOperand(0))->getOperand(1);
  const APInt *CmpC;
  if (!match(CmpOp1, m_APInt(CmpC)))
    return nullptr;

  if (Pred == ICmpInst::ICMP_UGT) {
    if (!CmpC->isSignMask())
      return nullptr;
  } else { // ICMP_EQ
    if (*CmpC != ExpectedMask)
      return nullptr;
  }

  // (X / DivC) + sext ((X & (SMin | (DivC - 1)) >u SMin) --> X >>s log2(DivC)
  // (X / DivC) + sext ((X & (SMin | (DivC - 1)) == (SMin | (DivC - 1))) --> X >>s log2(DivC)
  return BinaryOperator::CreateAShr(
      X, ConstantInt::get(Add.getType(), DivC->exactLogBase2()));
}
